38	struct common_chat_msg_content_part {
39	    std::string type;
40	    std::string text;
41	
42	    // TODO @ngxson : no known chat templates support reasoning_content in content parts yet
43	    //                this can be useful for models with interleaved thinking (like Kimi-K2)
44	    //                if you see any templates explicitly support this, please ping me
45	    // std::string reasoning_content;
46	
47	    bool operator==(const common_chat_msg_content_part & other) const {
48	        return type == other.type && text == other.text;
49	    }
50	};
51	
52	struct common_chat_template {
53	    jinja::program prog;
54	    std::string bos_tok;
55	    std::string eos_tok;
56	    std::string src;
57	    chat_template_caps caps;
58	
59	    common_chat_template(const std::string & src, const std::string & bos_token, const std::string & eos_token) {
60	        jinja::lexer lexer;
61	        auto lexer_res = lexer.tokenize(src);
62	        this->prog = jinja::parse_from_tokens(lexer_res);
63	
64	        this->src = lexer_res.source;
65	        this->bos_tok = bos_token;
66	        this->eos_tok = eos_token;
67	
68	        this->caps = jinja::caps_get(prog);
69	        // LOG_INF("%s: caps:\n%s\n", __func__, this->caps.to_string().c_str());
70	    }
71	
72	    const std::string & source() const { return src; }
73	    const std::string & bos_token() const { return bos_tok; }
74	    const std::string & eos_token() const { return eos_tok; }
75	
76	    chat_template_caps original_caps() const {
77	        return caps;
78	    }
79	};
80	
81	struct common_chat_msg {
82	    std::string                               role;
83	    std::string                               content;
84	    std::vector<common_chat_msg_content_part> content_parts;
85	    std::vector<common_chat_tool_call>        tool_calls;
86	    std::string                               reasoning_content;
87	    std::string                               tool_name;
88	    std::string                               tool_call_id;
89	
90	    nlohmann::ordered_json to_json_oaicompat(bool concat_typed_text = false) const;
91	
92	    bool empty() const {
93	        return content.empty() && content_parts.empty() && tool_calls.empty() && reasoning_content.empty() &&
94	               tool_name.empty() && tool_call_id.empty();
95	    }
96	
97	    void set_tool_call_ids(std::vector<std::string> &           ids_cache,
98	                           const std::function<std::string()> & gen_tool_call_id) {
99	        for (auto i = 0u; i < tool_calls.size(); i++) {
100	            if (ids_cache.size() <= i) {
101	                auto id = tool_calls[i].id;
102	                if (id.empty()) {
103	                    id = gen_tool_call_id();
104	                }
105	                ids_cache.push_back(id);
106	            }
107	            tool_calls[i].id = ids_cache[i];
108	        }
109	    }
110	
111	    bool operator==(const common_chat_msg & other) const {
112	        return role == other.role && content == other.content && content_parts == other.content_parts &&
113	               tool_calls == other.tool_calls && reasoning_content == other.reasoning_content &&
114	               tool_name == other.tool_name && tool_call_id == other.tool_call_id;
115	    }
116	
117	    bool operator!=(const common_chat_msg & other) const { return !(*this == other); }
118	};
119	
120	struct common_chat_msg_diff {
121	    std::string           reasoning_content_delta;
122	    std::string           content_delta;
123	    size_t                tool_call_index = std::string::npos;
124	    common_chat_tool_call tool_call_delta;
125	
126	    static std::vector<common_chat_msg_diff> compute_diffs(const common_chat_msg & msg_prv,
127	                                                           const common_chat_msg & msg_new);
128	
129	    bool operator==(const common_chat_msg_diff & other) const {
130	        return content_delta == other.content_delta && tool_call_index == other.tool_call_index &&
131	               tool_call_delta == other.tool_call_delta;
132	    }
133	};
