1292	// LFM2 format: uses <|tool_list_start|>[...]<|tool_list_end|> in system prompt
1293	// and <|tool_call_start|>[name(arg="val")]<|tool_call_end|> for tool calls.
1294	// - Reasoning: <think>{reasoning}</think> (optional)
1295	// - Content: text before a tool call (optional)
1296	// - Tool calls: Python-style, e.g. [function_name(arg1="value1", arg2="value2")]
1297	//   Tool calls can appear multiple times (parallel tool calls supported)
1298	static common_chat_params common_chat_params_init_lfm2(const common_chat_template &    tmpl,
1299	                                                       const autoparser::generation_params & inputs) {
1300	    common_chat_params data;
1301	
1302	    data.prompt            = common_chat_template_direct_apply_impl(tmpl, inputs);
1303	    data.format            = COMMON_CHAT_FORMAT_PEG_NATIVE;
1304	    data.supports_thinking = true;
1305	    data.preserved_tokens  = {
1306	        "<|tool_list_start|>",
1307	        "<|tool_list_end|>",
1308	        "<|tool_call_start|>",
1309	        "<|tool_call_end|>",
1310	        "<think>",
1311	        "</think>",
1312	    };
1313	
1314	    auto has_tools         = inputs.tools.is_array() && !inputs.tools.empty();
1315	    auto extract_reasoning = inputs.reasoning_format != COMMON_REASONING_FORMAT_NONE;
1316	    auto include_grammar   = has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE;
1317	
1318	    const std::string TOOL_CALL_START = "<|tool_call_start|>";
1319	    const std::string TOOL_CALL_END   = "<|tool_call_end|>";
1320	    const std::string THINK_START     = "<think>";
1321	    const std::string THINK_END       = "</think>";
