```cpp
static common_chat_params common_chat_params_init_your_model(
        const common_chat_template &          tmpl,
        const autoparser::generation_params & inputs) {

    common_chat_params data;

    // 1. Generate the prompt by applying the template
    data.prompt = common_chat_template_direct_apply_impl(tmpl, inputs);

    // 2. Set the format (usually PEG_NATIVE for custom parsing)
    data.format = COMMON_CHAT_FORMAT_PEG_NATIVE;

    // 3. List any special tokens that should be preserved during tokenization
    data.preserved_tokens = {
        "[SPECIAL_TOKEN_1]",
        "[SPECIAL_TOKEN_2]",
    };

    // 4. Set thinking/reasoning support if applicable
    data.supports_thinking = true;
    data.thinking_start_tag = "[THINK]";
    data.thinking_end_tag = "[/THINK]";

    // 5. Check what we need to parse
    auto has_tools = inputs.tools.is_array() && !inputs.tools.empty();
    auto extract_reasoning = inputs.reasoning_format != COMMON_REASONING_FORMAT_NONE;
    auto include_grammar = has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE;

    // 6. Build the PEG parser
    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        // p.literal("text")     - match literal string
        // p.content(...)        - tag content block
        // p.reasoning(...)      - tag reasoning block
        // p.tool_name(...)      - tag tool name
        // p.tool_args(...)      - tag tool arguments
        // p.until("marker")     - consume until marker
        // p.rest()              - consume remaining input
        // p.choice()            - alternatives
        // p.optional(...)       - optional block

        if (!has_tools) {
            return p.prefix(inputs.generation_prompt) << p.content(p.rest());
        }

        // Build parser for your specific format
        auto tool_choice = p.choice();
        foreach_function(inputs.tools, [&](const json & tool) {
            const auto & function = tool.at("function");
            std::string name = function.at("name");
            const auto & schema = function.at("parameters");

            // Build tool parser for this function
            auto tool_parser = p.tool(
                p.tool_open(p.tool_name(p.literal(name))) +
                p.tool_args(p.schema(p.json(), "tool-" + name, schema))
            );
            tool_choice |= p.rule("tool-" + name, tool_parser);
        });

        return p.prefix(inputs.generation_prompt) << p.content(p.rest()) << tool_choice;
    });

    data.parser = parser.save();

    // 7. Build grammar if needed
    if (include_grammar) {
        data.grammar_lazy = inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;
        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
            foreach_function(inputs.tools, [&](const json & tool) {
                auto schema = tool.at("function").at("parameters");
                builder.resolve_refs(schema);
            });
            parser.build_grammar(builder, data.grammar_lazy);
        });

        data.grammar_triggers = {
            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, "[TOOL_CALL]" }
        };
    }

    return data;
}
```

