1446	static common_chat_params common_chat_params_init_gigachat_v3(
1447	        const common_chat_template & tmpl,
1448	        const autoparser::generation_params & inputs) {
1449	
1450	    common_chat_params data;
1451	
1452	    data.prompt            = common_chat_template_direct_apply_impl(tmpl, inputs);
1453	    data.format            = COMMON_CHAT_FORMAT_PEG_NATIVE;
1454	    data.supports_thinking = false;
1455	    data.preserved_tokens  = {
1456	        "<|message_sep|>\n\n",
1457	        "<|role_sep|>\n",
1458	    };
1459	
1460	    auto has_tools         = inputs.tools.is_array() && !inputs.tools.empty();
1461	    auto include_grammar   = has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE;
1462	    const auto *tool_call_start_prefix = "<|message_sep|>\n\nfunction call<|role_sep|>\n";
1463	
1464	    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
1465	        auto ret = p.eps();
1466	        if (has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE) {
1467	            // Build a choice of all available tools
1468	            auto tool_choice = p.choice();
1469	            for (const auto & tool : inputs.tools) {
1470	                const auto & function = tool.at("function");
1471	                std::string name = function.at("name");
1472	                const auto & schema = function.at("parameters");
1473	
1474	                auto tool_name = p.json_member("name", "\"" + p.tool_name(p.literal(name)) + "\"");
1475	                auto tool_args = p.json_member("arguments", p.tool_args(p.schema(p.json(), "tool-" + name + "-schema", schema)));
1476	
1477	                auto tool_open = p.tool_open(p.literal("{") << tool_name);
1478	
1479	                tool_choice |= p.rule("tool-" + name, tool_open << "," << tool_args << "}");
1480	            }
1481	
1482	            // Define the tool call structure
1483	            auto min_calls = inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED ? 1 : 0;
1484	            auto max_calls = 1; // parallel toolcalls are not supported
1485	            auto tool_call = p.rule("tool-call", p.literal(tool_call_start_prefix) + tool_choice);
1486	            auto tool_calls = p.trigger_rule("tool-call-root", p.repeat(tool_call, /* min = */ min_calls, /* max = */ max_calls));
1487	
1488	            ret = p.content(p.until("<|message_sep|>\n\n")) << tool_calls;
1489	        } else {
1490	            // Content only parser
1491	            include_grammar = false;
1492	            ret = p.content(p.rest());
1493	        }
1494	
1495	        return p.literal(inputs.generation_prompt) + ret;
1496	    });
1497	
1498	    data.parser = parser.save();
1499	
1500	    if (include_grammar) {
1501	        data.grammar_lazy = has_tools && inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;
1502	
1503	        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
1504	            foreach_function(inputs.tools, [&](const json & tool) {
1505	                const auto & function = tool.at("function");
1506	                auto schema = function.at("parameters");
1507	                builder.resolve_refs(schema);
1508	            });
1509	            parser.build_grammar(builder, data.grammar_lazy);
1510	        });
1511	
1512	        data.grammar_triggers = {
1513	            {COMMON_GRAMMAR_TRIGGER_TYPE_WORD, tool_call_start_prefix}
1514	        };
1515	    }
1516	    return data;
1517	}
